CRYPTO_MACRO = [
    {"hero":True,"sub":"Macro & Central Banks","h3":"Fed holds rates as Warsh-led dot plot flips toward a hike","summary":"The FOMC kept rates at 3.50-3.75% but its updated projections erased the prior 2026 cut and signaled a possible hike.","body":["At Kevin Warsh's first meeting as chair on June 17, the Fed left the target range unchanged but turned more hawkish. Officials removed their earlier outlook for a cut this year and pushed any reductions into 2027 and 2028.","The median projection now points to a 3.8% funds rate by year end, leaving a hike on the table. Traders are pricing roughly an 80% chance of a December increase, with Fed officials citing elevated inflation tied partly to Middle East energy shocks."],"sources":[("CNBC","https://www.cnbc.com/2026/06/17/fed-interest-rate-decision-june-2026.html"),("Federal Reserve","https://www.federalreserve.gov/newsevents/pressreleases/monetary20260617a.htm")]},
    {"sub":"Macro & Central Banks","h3":"ECB raises rates 25bp in first hike since 2023 tightening cycle","summary":"The ECB lifted its deposit rate to 2.25%, citing inflation pressures driven by the Middle East conflict.","body":["The ECB raised all three key rates by 25 basis points effective June 17, putting the deposit, main refinancing and marginal lending rates at 2.25%, 2.40% and 2.65%. It was the first increase since the bank ended its aggressive tightening in September 2023.","Flash eurozone inflation hit 3.2% in May, the highest since September 2023. New staff projections see headline inflation averaging 3.0% in 2026 before easing to 2.0% by 2028."],"sources":[("European Central Bank","https://www.ecb.europa.eu/press/pr/date/2026/html/ecb.mp260611~4d41bd5e83.en.html")]},
    {"sub":"Macro & Central Banks","h3":"US PCE inflation climbs to 4.1% in May, hardening Fed stance","summary":"Headline PCE rose to 4.1% year over year in May while core PCE reached 3.4%, both above April readings.","body":["The Fed's preferred inflation gauge accelerated in May, with headline PCE up to 4.1% from 3.8% and core PCE rising to 3.4% from 3.3%. Energy prices linked to Middle East tensions added to the pressure.","The hotter print reinforced the central bank's reluctance to cut and kept markets weighing a possible late-year hike. The next reading is due July 30."],"sources":[("Trading Economics","https://tradingeconomics.com/united-states/pce-price-index-annual-change")]},
    {"sub":"Macro & Central Banks","h3":"Gold slips toward $4,000 as strong dollar offsets Iran peace bid","summary":"Gold headed for a roughly 5% weekly loss as the dollar hit a one-year high and oil retreated to pre-conflict levels.","body":["Bullion traded near $4,000 an ounce into Friday, on track for its worst week in months as a hawkish Fed and a stronger dollar outweighed safe-haven demand. The greenback climbed to its highest level in more than a year against major peers.","Oil prices unwound their conflict premium as US-Iran peace negotiations progressed, easing supply fears and reducing near-term inflation worries across commodity markets."],"sources":[("Profile News","https://www.profilenews.com/en/gold-prices-oil-global-markets-june-2026/"),("CNBC","https://www.cnbc.com/amp/2026/06/03/gold-holds-steady-amid-middle-east-tensions-us-economic-data-in-focus.html")]},
    {"sub":"Bitcoin & Ethereum","h3":"Bitcoin slides below $60,000 amid extreme fear","summary":"BTC traded around $59,000 on June 26, down from a year ago, with the Fear and Greed Index stuck at extreme fear.","body":["Bitcoin changed hands near $59,000 on Friday morning, roughly $2,300 below the prior day and about $48,000 lower than a year earlier. Forced liquidations wiped out hundreds of millions in leveraged longs during the slide.","The Crypto Fear and Greed Index sat at 24, deep in extreme-fear territory and in line with a depressed 30-day average. Sentiment has stayed weak through a stretch of heavy ETF redemptions."],"sources":[("Fortune","https://fortune.com/article/price-of-bitcoin-06-26-2026/")]},
    {"sub":"Bitcoin & Ethereum","h3":"Spot bitcoin ETFs bleed billions in record outflow streaks","summary":"US spot bitcoin ETFs saw a $691 million net outflow on June 25 as six straight weeks of redemptions topped $6 billion.","body":["Thursday's $691 million net outflow accelerated from Wednesday's $469 million, extending one of the heaviest institutional pullbacks of 2026. Total spot bitcoin ETF assets fell from about $104 billion to $94 billion over three weeks.","Deutsche Bank tied bitcoin's drop below $60,000 to a hawkish Fed, record ETF outflows and concerns over leveraged corporate holders. BlackRock's iShares fund led much of the selling."],"sources":[("CoinDesk","https://www.coindesk.com/markets/2026/06/23/bitcoin-s-recent-drop-below-usd60-000-signals-fed-etf-and-ai-pressures-deutsche-bank")]},
    {"sub":"Bitcoin & Ethereum","h3":"Ethereum hovers near $1,615 after 46% year-to-date collapse","summary":"ETH traded around $1,615, down sharply on the year, as staking ETF holders watched gains evaporate.","body":["Ether sat near $1,615, far below the $1,800-$1,900 zone analysts say it needs to reclaim for a stronger bullish case. The token is down about 46% year to date and well off its 2025 high.","A $10,000 stake in Grayscale's Ethereum mini trust held since January was worth roughly $5,328, as the price slide erased staking income. Holding above $1,650 remains seen as critical for any recovery."],"sources":[("MetaMask","https://metamask.io/price/ethereum"),("Yahoo Finance","https://finance.yahoo.com/markets/crypto/articles/10-000-grayscale-ethereum-staking-220053280.html")]},
    {"sub":"Bitcoin & Ethereum","h3":"Strategy sells bitcoin for first time in years to fund payouts","summary":"Strategy sold 32 BTC in early June to help cover preferred-stock distributions, breaking from its never-sell stance.","body":["The company offloaded 32 bitcoin on June 1 to fund payments to preferred shareholders, a small amount relative to its vast holdings but a notable signal from one of crypto's biggest corporate bulls.","Markets read the move as a sentiment shift, with bitcoin testing Strategy's average purchase price after the rare sale. The firm has restyled itself as a bitcoin treasury company."],"sources":[("24/7 Wall St.","https://247wallst.com/investing/2026/06/04/buy-sell-or-hold-mstr-after-strategys-first-bitcoin-sale-in-years/"),("Investing.com","https://www.investing.com/analysis/bitcoin-tests-microstrategys-average-buy-after-rare-btc-sale-200681432")]},
    {"sub":"Bitcoin & Ethereum","h3":"BlackRock staked ETH ETF passes rewards to investors","summary":"BlackRock's staked ether ETFs now route 2.8-3.5% annual staking yield to holders, drawing fresh inflows despite the price slump.","body":["BlackRock's iShares staked ethereum products pass staking rewards directly to investors, making ETH the first major crypto where mainstream buyers earn yield without running validators. ETHA has logged about $11.3 billion in cumulative inflows since launch.","The newer ETHB vehicle recorded fresh inflows in mid-June, lifting its assets above $548 million even as ether's price tested investor nerves."],"sources":[("BlackRock","https://www.blackrock.com/us/individual/products/348532/ishares-staked-ethereum-trust-etf"),("TipRanks","https://www.tipranks.com/news/cryptocurrencies/staked-ether-etf-sees-new-inflows-as-ethereum-price-slide-tests-investor-nerves")]},
    {"sub":"DeFi & Altcoins","h3":"Solana crosses 100 billion lifetime transactions","summary":"Solana became one of only two chains to top 100 billion lifetime transactions as institutional interest deepened.","body":["Solana joined ICP as the only blockchains to surpass 100 billion lifetime transactions, underscoring rapid network usage. Morgan Stanley filed for a Solana trust and spot SOL ETF assets passed $1 billion.","The network is processing the vast majority of on-chain tokenized equities volume and expanding in stablecoins and real-world assets. Its Alpenglow consensus upgrade aims to cut finality to 150 milliseconds, targeting a 2026 launch."],"sources":[("CryptoSlate","https://cryptoslate.com/a-solana-summer-could-lead-the-next-altcoin-rebound-if-bitcoin-holds-the-line/"),("Analytics Insight","https://www.analyticsinsight.net/amp/story/cryptocurrency-analytics-insight/solana-hits-1b-in-etfs-xrp-waits-on-the-clarity-act-while-kevin-oleary-shows-how-zkp-is-the-best-ai-infra-move")]},
    {"sub":"DeFi & Altcoins","h3":"XRP slides to $1.21 as traders await CLARITY Act","summary":"XRP fell about 8% on the week to $1.21 while Ripple expanded its RLUSD stablecoin into Turkey.","body":["XRP traded near $1.21, down roughly 8% on the week with bearish short-term and intermediate signals, as holders waited on US market-structure legislation. The CLARITY Act cleared the Senate Banking Committee in May.","Ripple pushed its RLUSD stablecoin into Turkey, targeting a market with nearly $200 billion in annual crypto volume. US XRP spot ETFs logged their strongest inflow month of 2026 in May."],"sources":[("Analytics Insight","https://www.analyticsinsight.net/amp/story/cryptocurrency-analytics-insight/solana-hits-1b-in-etfs-xrp-waits-on-the-clarity-act-while-kevin-oleary-shows-how-zkp-is-the-best-ai-infra-move")]},
    {"sub":"DeFi & Altcoins","h3":"DeFi losses top $840 million in 2026 as account hacks surge","summary":"Exploits have drained more than $840 million from DeFi this year, with compromised accounts now the leading attack vector.","body":["By early summer, DeFi protocols had lost over $840 million across dozens of attacks, with April standing as the single worst month in the sector's history after roughly $635 million was stolen. KelpDAO and Drift accounted for hundreds of millions.","Compromised accounts now drive more than half of all DeFi attacks by incident count, overtaking smart-contract bugs as the primary source of losses for the first time."],"sources":[("altFINS","https://altfins.com/blog/defi-hacks-2026/"),("CCN","https://www.ccn.com/education/crypto/defi-hacks-exploits-causes-crypto-stolen-2026/")]},
    {"sub":"DeFi & Altcoins","h3":"Stablecoin depegs expose minting-contract weaknesses","summary":"StablR and Resolv tokens lost their pegs this year after exploits let attackers mint unbacked supply.","body":["StablR's euro and dollar stablecoins broke their pegs on Ethereum in May after an exploit on the minting contract let an attacker extract about $2.8 million. The incident followed a similar pattern earlier in the year.","Resolv's USR stablecoin had depegged sharply in March when an attacker minted tens of millions in unbacked tokens and pulled roughly $23 million in value, sending the price down around 80%."],"sources":[("BeInCrypto","https://beincrypto.com/stablr-stablecoin-depeg-exploit/"),("Chainalysis","https://www.chainalysis.com/blog/lessons-from-the-resolv-hack/")]},
    {"sub":"DeFi & Altcoins","h3":"Total stablecoin supply tops $240 billion","summary":"Stablecoin supply surpassed $240 billion, with Tether holding above 67% share and Circle's USDC near 27%.","body":["Stablecoins kept expanding even amid the broader market slump, with total supply above $240 billion as of late spring. Tether's USDT held more than 67% of the market and Circle's USDC about 27%.","The growth comes as US regulators work to finalize rules under the GENIUS Act, which sets standards for reserve backing, redemption and supervision of dollar-backed tokens."],"sources":[("The Block","https://www.theblock.co/learn/406286/what-is-the-genius-act")]},
    {"sub":"Regulation & Policy","h3":"GENIUS Act stablecoin rules face July 18 deadline","summary":"Key implementing rules for US stablecoin oversight under the GENIUS Act take full effect on July 18.","body":["Federal agencies are racing to finalize stablecoin rules covering issuer licensing, capital, custody and anti-money-laundering standards, with the central provisions due to take effect July 18. The OCC and FDIC have issued proposed rulemakings, while Fed and Treasury rules remain pending.","A June comment window on a joint FinCEN-OFAC anti-money-laundering proposal added to a busy regulatory calendar as stablecoins move toward core finance."],"sources":[("Spazio Crypto","https://en.spaziocrypto.com/stablecoins/genius-act-stablecoin-deadlines-june-july-2026/"),("DL News","https://www.dlnews.com/articles/regulation/key-dates-for-us-crypto-regulation-in-2026/")]},
    {"sub":"Regulation & Policy","h3":"CLARITY Act advances to Senate floor calendar","summary":"The crypto market-structure bill was placed on the Senate Legislative Calendar, making it eligible for full floor consideration.","body":["On June 1 a new version of the Senate Banking bill was published and the CLARITY Act was placed under General Orders, formally clearing it for a floor vote. The Blockchain Association and 160 former national security officials urged leaders to pass it.","The legislation would establish a token taxonomy and divide oversight of digital assets, a long-sought framework for the industry."],"sources":[("Latham & Watkins","https://www.lw.com/en/us-crypto-policy-tracker/legislative-developments")]},
    {"sub":"Regulation & Policy","h3":"SEC names digital assets its top regulatory objective","summary":"The SEC's draft 2026-2030 strategic plan designates digital assets and distributed ledger technology as its first goal.","body":["The SEC published a draft strategic plan for fiscal years 2026 through 2030 that lists digital assets and distributed ledger technology as its leading regulatory objective. The move signals a more structured approach to crypto oversight.","It builds on earlier joint SEC and CFTC guidance that set out a token taxonomy spanning digital commodities, collectibles, tools, stablecoins and securities."],"sources":[("Latham & Watkins","https://www.lw.com/en/us-crypto-policy-tracker/regulatory-developments")]},
    {"sub":"Regulation & Policy","h3":"Institutions cut spot bitcoin ETF positions 17% in Q1","summary":"Institutional holders trimmed their spot bitcoin ETF exposure from 313K to 261K BTC in the first quarter.","body":["Institutional investors reduced positions in US spot bitcoin ETFs by about 17% in the first quarter, from roughly 313,000 to 261,000 BTC. The retreat foreshadowed the heavy outflows that followed through June.","Analysts remain split on the trend, with some calling the redemptions noise as Wall Street builds longer-term crypto infrastructure, while others see a genuine reassessment of risk."],"sources":[("Bitcoin Foundation","https://bitcoinfoundation.org/news/crypto-etfs-news/etf-outflows-june-first-week/"),("CoinDesk","https://www.coindesk.com/coindesk-news/2026/06/02/bitcoin-etf-outflows-are-noise-as-wall-street-doubles-down-on-crypto-says-analyst")]},
]

MENTAL_HEALTH = [
    {"hero":True,"sub":"Research & Studies","h3":"Nearly 1 in 5 US teens use AI chatbots for mental health advice","summary":"A JAMA Pediatrics study found about a fifth of US adolescents and young adults turn to AI chatbots for mental health guidance.","body":["The nationally representative survey of those aged 12 to 21, conducted in late 2025 and published June 1, found roughly one in five reported using AI chatbots for mental health advice. Many used them repeatedly and rated the guidance as helpful.","Researchers warned that AI is already embedded in young people's mental health information ecosystem, urging parents and clinicians to discuss chatbot use and steer teens toward evidence-based care."],"sources":[("JAMA Pediatrics","https://jamanetwork.com/journals/jamapediatrics/fullarticle/2849307"),("RAND","https://www.rand.org/news/press/2026/06/nearly-1-in-5-us-adolescents-and-young-adults-use-ai.html")]},
    {"sub":"Research & Studies","h3":"People with depression want validation with clear limits from chatbots","summary":"A JMIR Mental Health qualitative study mapped how people with lived experience evaluate LLM-based mental health tools.","body":["The lived-experience study found users with depression weigh actionable information, emotional validation with clear boundaries and personalization that does not force unsafe data disclosure. Participants valued chatbots as complements rather than replacements for human support.","The authors offered concrete design strategies to reduce harm, positioning LLM tools as aids to recovery and human care rather than substitutes."],"sources":[("JMIR Mental Health","https://mental.jmir.org/2026/1/e78288")]},
    {"sub":"Research & Studies","h3":"Trial tests automated therapy app against a general chatbot","summary":"A JMIR feasibility randomized trial compared a fully automated mobile therapeutic with a general chatbot for depression and anxiety.","body":["The feasibility randomized controlled trial measured whether a purpose-built mobile therapeutic outperformed a general chatbot in cutting depression and anxiety and lifting well-being. It adds to a thin evidence base on structured versus open-ended AI tools.","Such head-to-head designs are increasingly important as clinicians weigh which AI formats are safe and effective enough for real-world mental health use."],"sources":[("JMIR Mental Health","https://mental.jmir.org/2026/1/e82642")]},
    {"sub":"Research & Studies","h3":"Media coverage of AI mental health harms skews toward youth suicide","summary":"A JMIR scoping review found news reporting on AI chatbot psychiatric harms clusters around severe outcomes among young people.","body":["The rapid scoping review of mass-media narratives found coverage of generative AI psychiatric adverse events concentrates on the most severe outcomes, particularly suicide deaths among youth. Stories are often framed around regulatory and corporate accountability.","The authors suggest this framing shapes public and policymaker perceptions of AI mental health risk, potentially crowding out nuance about benefits and design fixes."],"sources":[("JMIR Mental Health","https://mental.jmir.org/2026/1/e93040")]},
    {"sub":"Research & Studies","h3":"WHO issues ethics guidance for AI multimodal models in health","summary":"The WHO released governance guidance for large multimodal models, urging transparency and oversight proportionate to risk.","body":["Published in late March, the WHO guidance addresses large multimodal models entering healthcare, calling for rigorous evaluation, transparency and risk-proportionate oversight. It flagged extensive use of LLMs by people facing anxiety, depression and crisis.","The agency cautioned that these systems can produce confident but incomplete or inaccurate responses and may fail to flag when a concern needs a trained professional."],"sources":[("Patient Safety Learning hub","https://www.pslhub.org/learn/digital-health-and-care-service-provision/288_artificial-intelligence/380_large-language-models-llms-and-generative-ai/ethics-and-governance-of-artificial-intelligence-for-health-guidance-on-large-multi-modal-models-who-25-march-2026-r14246/")]},
    {"sub":"Research & Studies","h3":"Studies split on whether AI companions ease or worsen loneliness","summary":"New research finds AI companions can reduce loneliness on par with human contact, but heavy use may deepen isolation.","body":["A Harvard Business School study found interacting with an AI companion eased loneliness about as much as talking to another person, with users citing the sense of feeling heard. Stanford work suggested chatbots can help lonely people feel supported.","Other research warns that excessive use can erode social skills, foster emotional dependence and increase withdrawal, and that companion bots can exploit teenagers' emotional needs in harmful ways."],"sources":[("APA","https://www.apa.org/monitor/2026/01-02/trends-digital-ai-relationships-emotional-connection"),("Stanford Report","https://news.stanford.edu/stories/2025/08/ai-companions-chatbots-teens-young-people-risks-dangers-study")]},
    {"sub":"Tools & Applications","h3":"FDA advisory committee weighs generative AI mental health devices","summary":"An FDA committee debated how to regulate generative AI mental health tools, stressing human oversight and safety monitoring.","body":["The FDA has authorized more than 1,200 AI-enabled medical devices but none for mental health uses, and the agency is only now building a framework for generative AI tools in the space. The advisory committee emphasized physician oversight and suicide-risk monitoring.","Early January guidance on low-risk devices and clinical decision support hinted the FDA may treat more AI apps as wellness products outside formal regulation, raising questions about evidence standards."],"sources":[("Psychiatric Times","https://www.psychiatrictimes.com/view/fda-committee-meets-on-generative-ai-digital-mental-health-devices"),("Sidley Austin","https://www.sidley.com/en/insights/newsupdates/2025/11/us-fda-and-cms-actions-on-generative-ai-enabled-mental-health-devices-yield-insights-across-ai")]},
    {"sub":"Tools & Applications","h3":"Slingshot AI scales Ash therapy chatbot after $93M raise","summary":"a16z-backed Slingshot AI expanded its Ash mental health chatbot, which has been tested by tens of thousands of beta users.","body":["Slingshot AI, which has raised about $93 million, is pushing its Ash chatbot as a tool to bridge the therapy gap with round-the-clock support. The product has run through roughly 50,000 beta users.","The launch reflects a wave of venture money chasing AI therapy even as clinicians and regulators debate safety, evidence and the limits of automated mental health support."],"sources":[("TechFundingNews","https://techfundingnews.com/slingshot-unveils-ash-ai-chatbot-designed-to-bridge-the-therapy-gap-24-7/"),("Behavioral Health Business","https://bhbusiness.com/2025/07/22/with-93m-raised-slingshot-slingshot-ai-debuts-ai-powered-therapy-service/")]},
    {"sub":"Tools & Applications","h3":"Wysa deepens clinical footprint through NHS and NIH-funded work","summary":"Wysa is expanding via NHS partnerships, employer assistance programs and an NIH grant for chronic-pain mental health support.","body":["Wysa is available through workplace assistance programs at major employers across healthcare, finance and technology, and landed a $3.4 million NIH grant for personalized support tied to chronic pain. It also acquired companies in virtual behavioral health and physical therapy.","The push contrasts with Woebot, the CBT chatbot pioneer that shut its consumer app and shifted to an enterprise-only model despite strong trial evidence."],"sources":[("PDP Spectra","https://pdpspectra.com/blog/ai-mental-health-tech-2026/"),("Telehealth.org","https://telehealth.org/news/ai-psychotherapy-shutdown-what-woebots-exit-signals-for-clinicians/")]},
    {"sub":"Tools & Applications","h3":"Researchers push for informed consent in training mental health AI","summary":"An npj Digital Medicine piece argues patients should consent before their data trains mental health AI systems.","body":["The npj Digital Medicine article calls for reclaiming informed consent when patient data is used to train mental health AI, warning that current practices often sideline the people whose records fuel these models.","It joins a growing literature scrutinizing the evidence, device lineage and regulatory gaps behind FDA-authorized mental health software, where requirements can be inconsistent."],"sources":[("npj Digital Medicine","https://www.nature.com/articles/s41746-026-02843-8"),("npj Mental Health Research","https://www.nature.com/articles/s44184-025-00174-2")]},
]
